SELECT isnull(a.employee_id,0) as employee_id, fdd.label as hobby, isnull(a.attribute1,CASE fdd.label WHEN '爱好' THEN '爱好特长' ELSE '个人技能' END) as attribute1, a.level_mechanism, a.enabled_flag FROM fnd_dict left join fnd_dict_detail fdd on fnd_dict.id=fdd.dict_id LEFT JOIN ( SELECT employee_id, hobby, attribute1, stuff ( ( SELECT '，' + level_mechanism + '' FROM pm_employee_hobby b WHERE a.employee_id = b.employee_id AND a.hobby = b.hobby AND b.enabled_flag = 1 FOR XML PATH ( '' ) ), 1, 1, '' ) AS level_mechanism, enabled_flag FROM pm_employee_hobby a WHERE 1 = 1
and a.employee_id = #{criteria.employeeId,jdbcType=BIGINT}
and a.enabled_flag = #{criteria.enabled,jdbcType=BIT}
GROUP BY employee_id, hobby, attribute1, enabled_flag ) a ON fdd.label = a.hobby WHERE fnd_dict.name='hobby_type' -- fdd.dict_id = 65 order by fdd.sort

